import { useLocation } from "react-router-dom";
import styled from "styled-components";

const allProducts = [
  { id: 1, name: "iPhone 15", category: "celular" },
  { id: 2, name: "Galaxy S23", category: "celular" },
  { id: 3, name: "JBL 520BT", category: "headphone" },
  { id: 4, name: "Notebook Gamer", category: "notebook" },
  { id: 5, name: "Mouse RGB", category: "acessorios" }
];

const Products = () => {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const categoria = queryParams.get("categoria");

  const filteredProducts = categoria
    ? allProducts.filter(p => p.category === categoria)
    : allProducts;

  return (
    <Container>
      <Title>
        {categoria ? `Categoria: ${categoria}` : "Todos os Produtos"}
      </Title>

      <Grid>
        {filteredProducts.map((product) => (
          <Card key={product.id}>
            {product.name}
          </Card>
        ))}
      </Grid>
    </Container>
  );
};

export default Products;
